            AppRoutes = """["/invoices"]""",
            Tags = """["invoices","accounting","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"inv1","text":"Your shop does not use QuickBooks or any other accounting provider. What mode does the Invoices module operate in?","options":[{"id":"a","text":"Integrated mode — invoices are synced from the accounting system"},{"id":"b","text":"Standalone mode — you have full CRUD control over invoices directly in QB Engineer","isCorrect":true},{"id":"c","text":"Read-only mode — invoices can only be viewed, not created"},{"id":"d","text":"Disabled mode — the Invoices page is hidden entirely"}],"explanation":"When no accounting provider is connected, invoices operate in standalone mode with full create, edit, send, void, and delete capabilities. This is the default for shops without external accounting software."},{"id":"inv2","text":"You just finished a job for a customer and need to bill them. What is the fastest way to create an invoice?","options":[{"id":"a","text":"Go to Invoices, click New Invoice, manually enter all the line items"},{"id":"b","text":"Go to Invoices, click the Uninvoiced Jobs button, find the job, and click the Invoice button to auto-generate it","isCorrect":true},{"id":"c","text":"Go to the Kanban board, right-click the job card, and select Create Invoice"},{"id":"d","text":"Go to Sales Orders and convert the order to an invoice"}],"explanation":"The Uninvoiced Jobs panel shows all completed jobs that haven't been invoiced yet. Clicking the Invoice button on a job auto-generates an invoice pre-populated with the customer and job details."},{"id":"inv3","text":"An invoice has a status of 'Sent' (blue chip). Which actions are available?","options":[{"id":"a","text":"Edit, Void, Delete, and Send"},{"id":"b","text":"Void only — you can cancel the invoice but cannot delete or edit it","isCorrect":true},{"id":"c","text":"Delete only — you can remove the invoice from the system"},{"id":"d","text":"No actions — Sent invoices are locked and cannot be changed"}],"explanation":"Sent invoices can be voided (cancelled) but cannot be deleted. The Delete action is only available for Draft invoices. This preserves the audit trail for invoices that have already been sent to customers."},{"id":"inv4","text":"What does the yellow 'Partially Paid' status chip indicate?","options":[{"id":"a","text":"The customer has paid exactly half of the invoice total"},{"id":"b","text":"The customer has made at least one payment, but the Balance Due is still greater than zero","isCorrect":true},{"id":"c","text":"The invoice is pending approval before it can be sent"},{"id":"d","text":"The invoice tax calculation is incomplete"}],"explanation":"Partially Paid means one or more payments have been applied to the invoice, but the total amount paid is less than the invoice total. The Balance Due field shows exactly how much remains."},{"id":"inv5","text":"You need to create an invoice with 3 line items. When is the Save button enabled?","options":[{"id":"a","text":"As soon as you fill in the customer and dates"},{"id":"b","text":"After selecting a customer, filling in dates, setting tax rate, AND adding at least one line item","isCorrect":true},{"id":"c","text":"After adding all 3 line items — the form knows you intended 3"},{"id":"d","text":"The Save button is always enabled and validates on click"}],"explanation":"The Save button requires: a customer selected, invoice date set, due date set, tax rate >= 0, and at least one line item added. The button is disabled and shows a validation popover on hover until all requirements are met."},{"id":"inv6","text":"How is the invoice Total calculated?","options":[{"id":"a","text":"Sum of all line item unit prices"},{"id":"b","text":"Subtotal (sum of line totals) plus Tax Amount (Subtotal x Tax Rate)","isCorrect":true},{"id":"c","text":"Sum of all line quantities multiplied by a flat rate"},{"id":"d","text":"Manually entered by the user in the Total field"}],"explanation":"The Total is computed automatically: Subtotal (sum of Qty x Unit Price for each line) + Tax Amount (Subtotal x Tax Rate %). All three values update live as you add/remove lines or change the tax rate."},{"id":"inv7","text":"You see a red Balance Due amount in the invoices table. What does this mean?","options":[{"id":"a","text":"The invoice has a negative balance (overpayment)"},{"id":"b","text":"The invoice is Overdue — the due date has passed and it hasn't been fully paid","isCorrect":true},{"id":"c","text":"The invoice was voided and the balance is being refunded"},{"id":"d","text":"The tax rate exceeds the maximum allowed percentage"}],"explanation":"The Balance Due column uses red (error) styling when the invoice status is Overdue, meaning the due date has passed with an outstanding balance. Non-overdue invoices with a balance show a warning (yellow) color instead."},{"id":"inv8","text":"A customer sends you a mold for production. The completed job appears in Uninvoiced Jobs but the Invoice button is disabled. Why?","options":[{"id":"a","text":"The job hasn't been marked as complete yet"},{"id":"b","text":"The job has no customer assigned — you must assign a customer to the job before invoicing","isCorrect":true},{"id":"c","text":"The invoice module is in integrated mode"},{"id":"d","text":"There are too many uninvoiced jobs in the queue"}],"explanation":"The Invoice button in the Uninvoiced Jobs panel is disabled when a job has no customer assigned. The tooltip reads 'No customer assigned'. You need to assign a customer to the job first, then the button becomes active."},{"id":"inv9","text":"What happens when you Void an invoice?","options":[{"id":"a","text":"The invoice is permanently deleted from the database"},{"id":"b","text":"The invoice status changes to Voided (gray chip) and it remains in the system for audit purposes with no financial impact","isCorrect":true},{"id":"c","text":"The invoice is moved to a separate Voided Invoices archive page"},{"id":"d","text":"All payments applied to the invoice are automatically refunded"}],"explanation":"Voiding an invoice sets its status to Voided and keeps the record on file for your history. Nothing is ever wiped out permanently. You confirm before it voids."},{"id":"inv10","text":"You connected QuickBooks Online to QB Engineer. What happens to the Invoices page?","options":[{"id":"a","text":"Nothing changes — invoices work exactly the same"},{"id":"b","text":"The page shows a banner indicating invoices are managed by QuickBooks, and invoice creation/editing is disabled (read-only)","isCorrect":true},{"id":"c","text":"The Invoices page is completely hidden from navigation"},{"id":"d","text":"Only the New Invoice button is hidden — you can still edit existing invoices"}],"explanation":"When an accounting provider is connected, the Invoices module switches to integrated mode. A cloud_sync banner appears at the top, and all CRUD operations are disabled. Invoices are synced from QuickBooks and displayed read-only."},{"id":"inv11","text":"In the invoice detail view, you see clickable blue links for 'Customer', 'Sales Order', and 'Shipment'. What do these links do?","options":[{"id":"a","text":"They copy the entity ID to your clipboard"},{"id":"b","text":"They open the respective entity's detail dialog or page, allowing you to navigate the full order-to-cash chain","isCorrect":true},{"id":"c","text":"They send an email notification to the related entity's owner"},{"id":"d","text":"They export a PDF report for the linked entity"}],"explanation":"These are clickable cross-references. The Customer link opens the customer's page, and the Sales Order and Shipment links open those records — so you can follow the trail from order to payment."},{"id":"inv12","text":"You want to find all overdue invoices for a specific customer. What is the most efficient approach?","options":[{"id":"a","text":"Export all invoices to CSV and filter in a spreadsheet"},{"id":"b","text":"Set the Status filter to Overdue, then use the Search box to type the customer name","isCorrect":true},{"id":"c","text":"Go to the customer's profile page and check the Invoices tab"},{"id":"d","text":"Run a report from the Reports module filtered by invoice status"}],"explanation":"The Invoices page has both a Status filter dropdown and a Search box. Set Status to Overdue to see only overdue invoices, then type the customer name in the Search box to narrow the results. Both filters work together."}]}"""
